{
  "name": "TwixAi Studio",
  "description": "An AI-powered design studio to create stunning visuals, logos, social media posts, and more.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React, { useState, useRef, useEffect } from 'react';
import LogoIcon from './icons/LogoIcon';
import TextIcon from './icons/TextIcon';
import MediaIcon from './icons/MediaIcon';
import BarChartIcon from './icons/BarChartIcon';
import CalendarIcon from './icons/CalendarIcon';
import MicrophoneIcon from './icons/MicrophoneIcon';
import FolderIcon from './icons/FolderIcon';
import ChatHistoryPanel from './ChatHistoryPanel';
import type { Conversation, ActiveView } from '../types';

interface HeaderProps {
  activeView: ActiveView;
  setActiveView: (view: ActiveView) => void;
  conversations: Conversation[];
  activeConversationId: string | null;
  onSelectConversation: (id: string) => void;
  onNewConversation: () => void;
  onDeleteConversation: (id: string) => void;
}

const Header: React.FC<HeaderProps> = ({ 
  activeView, 
  setActiveView,
  conversations,
  activeConversationId,
  onSelectConversation,
  onNewConversation,
  onDeleteConversation
}) => {
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const historyRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (historyRef.current && !historyRef.current.contains(event.target as Node)) {
        setIsHistoryOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const NavButton = ({ view, label, icon }: { view: ActiveView, label: string, icon: React.ReactNode }) => (
    <button
      onClick={() => setActiveView(view)}
      className={`flex items-center gap-2 px-3 py-2 rounded-full text-sm font-bold transition-colors ${
        activeView === view
          ? 'bg-white text-black shadow-md border border-black'
          : 'text-text-secondary hover:bg-white/10'
      }`}
    >
      {icon}
      <span className="hidden md:inline">{label}</span>
    </button>
  );

  return (
    <header className="fixed top-0 left-0 w-full bg-bg-primary/80 backdrop-blur-md border-b border-border-primary z-20">
      <div className="max-w-7xl mx-auto px-4 sm:px-8 flex items-center justify-between h-20">
        <div className="flex items-center gap-3">
          <LogoIcon className="h-8 w-8" />
          <h1 className="text-xl font-bold text-text-primary">TwixAi</h1>
        </div>
        <nav className="flex items-center gap-4">
          {activeView === 'content' && (
            <div className="relative" ref={historyRef}>
              <button 
                onClick={() => setIsHistoryOpen(o => !o)} 
                className="flex items-center gap-2 px-4 py-2 rounded-full text-sm font-bold transition-colors bg-white border border-black text-black hover:bg-slate-100 shadow-sm"
              >
                <FolderIcon className="h-5 w-5" />
                Historial
              </button>
              {isHistoryOpen && (
                <div className="absolute top-full right-0 mt-2 z-30 w-72 bg-white rounded-lg shadow-xl border border-slate-200">
                  <ChatHistoryPanel
                    conversations={conversations}
                    activeConversationId={activeConversationId}
                    onSelectConversation={(id) => {
                      onSelectConversation(id);
                      setIsHistoryOpen(false);
                    }}
                    onNewConversation={() => {
                      onNewConversation();
                      setIsHistoryOpen(false);
                    }}
                    onDeleteConversation={onDeleteConversation}
                  />
                </div>
              )}
            </div>
          )}
          <div className="flex items-center gap-1 p-1 bg-bg-secondary/50 rounded-full border border-border-primary overflow-x-auto no-scrollbar max-w-[60vw] md:max-w-none">
            <NavButton view="content" label="Contenido" icon={<TextIcon className="h-5 w-5" />} />
            <NavButton view="multimedia" label="Multimedia" icon={<MediaIcon className="h-5 w-5" />} />
            <NavButton view="analytics" label="Análisis" icon={<BarChartIcon className="h-5 w-5" />} />
            <NavButton view="calendar" label="Calendario" icon={<CalendarIcon className="h-5 w-5" />} />
            <NavButton view="live" label="En Vivo" icon={<MicrophoneIcon className="h-5 w-5" />} />
          </div>
        </nav>
      </div>
    </header>
  );
};

export default Header;
